var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아이들을 데리고 온 뒤 작동을 멈췄어. 상태는 어때 보여?","JPN":"子供たちを連れ帰った後、動かなくなったよ。どういう状態かしら？","ENG":"It stopped working after it came back with the children. What do you think is the problem?","TWN":"它將孩子們帶回來後便停止運作，看起來情況如何？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"파손된 곳은 없다. 단순히 동력이 부족해서 멈춘 것 같군.","JPN":"壊れたところはない。単に動力不足で止まったようだな。","ENG":"Nothing’s been damaged. Maybe it stopped working simply because it needs power.","TWN":"沒有毀損的地方，應該只是單純動力不足。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다시 움직이게 하려면 병기마의 사양에 맞는 강력한 동력원이 필요해.","JPN":"また動かすためには、兵器馬の仕様に合う強力な動力源が必要だ。","ENG":"To get it started again I’ll need a powerful generator that fits the Armored Horse's specifications.","TWN":"想讓它再次動起來的話，需要符合戰馬規格的強大動能。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"수송 차량에 쓰는 예비용 배터리가 있어. 그걸로 동력을 공급해 볼 수 없을까?","JPN":"輸送車両に使う予備用のバッテリーがあるけど、それで動力を供給することはできない？","ENG":"There's a spare battery left for the transport vehicle. Will that be enough power it?","TWN":"有運輸車輛的備用電池，可以用那個來提供動力嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"유감이지만 자동차 배터리로 병기마를 움직일 수는 없어.","JPN":"残念だが、自動車のバッテリーで兵器馬を動かすことはできない。","ENG":"I'm afraid not. A car battery’s not enough to move an Armored Horse.","TWN":"很遺憾，汽車電池是無法讓戰馬動起來的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"흐음… 원인을 알고 있다니 다행이네.","JPN":"ふうん……原因がわかるならよかった。","ENG":"Hmm... I'm relieved you know what the cause is.","TWN":"嗯嗯……幸好你還知道原因。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"무슨 뜻이지?","JPN":"どういうことだ？","ENG":"What's that supposed to mean?","TWN":"什麼意思？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"자기가 타고 다니던 병기마에 대한 지식은 잊지 않은 것 같아서 말이야.","JPN":"自分が乗っていた兵器馬についての知識は忘れてないみたいだから。","ENG":"That you haven't forgotten anything about the Armored Horse you came here on.","TWN":"就是你沒有忘記關於你騎過的戰馬的知識。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 병기마를 어딘가에서 훔쳤을 뿐이라면, 방금처럼 보자마자 판단하진 못했을 테니까.","JPN":"どこかで兵器馬を盗んだだけなら、今のように見てすぐ判断できなかっただろうね。","ENG":"If you had stolen it from somewhere, you wouldn't be able to know the cause, right?","TWN":"如果戰馬是你不知道從哪偷來的，那你應該就不會說出剛才那番話。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아직도 의심 받고 있었나? 유감이군.","JPN":"まだ疑っていたのか？　残念だな。","ENG":"Are you still doubting me? Ugh..","TWN":"你還在懷疑我嗎？真是遺憾。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"미안. 대신 저녁으로 감자 요리 대접할게.","JPN":"ごめん。その代わり、夕飯はジャガイモの料理をごちそうするから。","ENG":"Sorry. I'll treat you to some potatoes for dinner.","TWN":"抱歉，晚上請你吃馬鈴薯料理以表歉意吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 그 전에, 먼저 만나 봐야 할 친구들이 있어.","JPN":"でもその前に、あの子たちに会わないとね。","ENG":"But before we do that I need to see some friends of mine.","TWN":"不過在那之前，你得先見一些人。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"친구들?","JPN":"あの子たち？","ENG":"\\"Friends\\"?","TWN":"見誰？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고철 수집이라고?","JPN":"鉄くず拾い？","ENG":"Gathering scrap metal you say?","TWN":"收集廢鐵？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"네. 외성 밖을 돌아다니다 보면 쓸 만한 골동품을 찾을 수 있거든요.","JPN":"うん。外郭の外を歩いてると、使えそうな骨董品が見つかるんだ。","ENG":"Uh-huh. There are a lot of valuable antiques outside the castle.","TWN":"對，在外城外繞繞的話，應該可以找到還能用的古董。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 아이들끼리 침식지대로 나가는 건 위험하진 않나?","JPN":"でも子供たちだけで侵食地帯に出るのは危ないはずでは？","ENG":"But isn't it dangerous for children to be out there in the Corrupted Areas?","TWN":"但是小朋友去侵蝕地帶不會有危險嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"너무 멀리 나가지만 않으면 괜찮댔어요! 좋은 고철을 찾으면 돈도 많이 벌고요!","JPN":"あまり遠くまで行かなければ大丈夫なんだって！　いい鉄くずを見つけたらお金もいっぱいもらえるし！","ENG":"They said it was okay as long as we don't stray too far! And we can make money if we find something good!","TWN":"只要不走太遠就好啦！找到好的廢鐵可以賺很多錢喔！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}}]`);export{e as default};